/* Tier-2 C-level fixture: newlib vfprintf format-specifier coverage.
 *
 * Phase rule (rt_c_helpers.h): the vsim span (phase 2) is I/O-free. Format
 * lines are produced via newlib's vsnprintf in QEMU2 (phase 3) and emitted
 * with rt_semihost_writes -- exercising signed int, hex, string, char,
 * pointer, width/zero-pad/left-align in the same vfprintf code path that
 * printf would walk, just routed through semihosting instead of
 * libgloss/sim_control MMIO.
 *
 * No floating-point format specifiers: %f drags the soft-float / iprintf
 * library and is unnecessary for proving the format machinery is intact.
 */
#include "runtime/rt_c_helpers.h"
#include <stdint.h>
#include <stdio.h>

static void emit_fmt(const char* fmt, ...)
{
  char    buf[160];
  va_list ap;
  va_start(ap, fmt);
  vsnprintf(buf, sizeof buf, fmt, ap);
  va_end(ap);
  buf[sizeof buf - 1] = '\0';
  rt_semihost_writes(buf);
}

