 *
 * No floating-point format specifiers: %f drags the soft-float / iprintf
 * library and is unnecessary for proving the format machinery is intact.
 */
#include "runtime/rt_c_helpers.h"
#include <stdint.h>
#include <stdio.h>

static void emit_fmt(const char* fmt, ...)
{
  char    buf[160];
  va_list ap;
  va_start(ap, fmt);
  vsnprintf(buf, sizeof buf, fmt, ap);
  va_end(ap);
  buf[sizeof buf - 1] = '\0';
